components.css:
.ds-def-card {
  background: #fbf8f3;
  border: 1px solid #2a221c;
  padding: 28px 32px;
  margin: 24px 0;
  position: relative;
  box-shadow: 4px 4px 0 #2a221c;
  border-radius: 0;
}
.ds-def-tag {
  position: absolute;
  top: -11px;
  left: 24px;
  background: #1a1612;
  color: #fbf8f3;
  padding: 3px 14px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  border-radius: 0;
}
.ds-def-title {
  font-family: 'Fraunces', Georgia, serif;
  font-style: italic;
  font-size: 22px;
  font-weight: 500;
  margin-bottom: 10px;
  color: #c44536;
}
.ds-def-body {
  font-family: 'Fraunces', Georgia, serif;
  font-size: 16px;
  line-height: 1.65;
}
.ds-def-body p {
  max-width: none;
  margin-bottom: 10px;
}
.ds-hl-p {
  color: #c44536;
  font-weight: 700;
}

.ds-thm {
  background: #1a1612;
  color: #fbf8f3;
  padding: 32px 36px;
  margin: 32px 0;
  position: relative;
  border-radius: 2px;
}
.ds-thm::before {
  content: "";
  position: absolute;
  top: 8px;
  left: 8px;
  right: -8px;
  bottom: -8px;
  border: 1px solid #2a221c;
  z-index: -1;
}
.ds-thm-tag {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.3em;
  color: #d4a017;
  margin-bottom: 6px;
}
.ds-thm-title {
  font-family: 'Fraunces', Georgia, serif;
  font-size: 26px;
  font-style: italic;
  font-weight: 500;
  margin-bottom: 14px;
}
.ds-thm-body {
  font-size: 16px;
  line-height: 1.6;
}
.ds-thm-body p {
  max-width: none;
}
.ds-thm-body ol {
  padding-left: 24px;
  margin-top: 8px;
}
.ds-thm-body li {
  margin-bottom: 8px;
}

.ds-intuition {
  background: linear-gradient(135deg, rgba(212,160,23,0.08), rgba(196,69,54,0.04));
  border-left: 4px solid #d4a017;
  padding: 22px 28px;
  margin: 24px 0;
  font-style: italic;
  font-size: 17px;
  font-family: 'Fraunces', Georgia, serif;
  line-height: 1.65;
  color: #1a1612;
  border-radius: 0;
}
.ds-intuition::before {
  content: "INTUITION";
  display: block;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-style: normal;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.25em;
  color: #d4a017;
  margin-bottom: 8px;
  text-transform: uppercase;
}

.ds-sketch {
  border: 1px dashed #6b5d4f;
  padding: 18px 24px;
  margin: 16px 0;
  font-size: 15px;
  background: rgba(251,248,243,0.4);
  font-family: 'Fraunces', Georgia, serif;
  line-height: 1.65;
  color: #1a1612;
  border-radius: 0;
}
.ds-sketch-tag {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.25em;
  color: #6b5d4f;
  margin-bottom: 6px;
  text-transform: uppercase;
}
.ds-sketch p {
  max-width: none;
  font-size: 15px;
}

.ds-panel {
  background: #fbf8f3;
  border: 1px solid #2a221c;
  padding: 28px;
  margin: 32px 0;
  border-radius: 2px;
  box-shadow: 6px 6px 0 rgba(26,22,18,0.08);
}
.ds-panel-header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  border-bottom: 1px dashed #2a221c;
  padding-bottom: 12px;
  margin-bottom: 20px;
}
.ds-panel-title {
  font-family: 'Fraunces', Georgia, serif;
  font-style: italic;
  font-size: 22px;
  color: #1a1612;
}
.ds-panel-tag {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 10px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #6b5d4f;
}
.ds-num-picker {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin: 16px 0 20px;
}
.ds-num-btn {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 14px;
  font-weight: 500;
  padding: 8px 14px;
  background: #f5f1ea;
  border: 1px solid #2a221c;
  cursor: pointer;
  transition: all 0.18s cubic-bezier(0.22, 0.68, 0.35, 1.0);
  color: #1a1612;
  border-radius: 0;
}
.ds-num-btn:hover {
  background: #e8e1d4;
  transform: translateY(-1px);
}
.ds-num-btn-active {
  background: #1a1612;
  color: #fbf8f3;
  transform: translateY(-1px);
  box-shadow: 2px 2px 0 #c44536;
}

.ds-btn-primary {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 14px;
  font-weight: 500;
  padding: 8px 14px;
  background: #f5f1ea;
  color: #1a1612;
  border: 1px solid #2a221c;
  cursor: pointer;
  transition: all 0.18s cubic-bezier(0.22, 0.68, 0.35, 1.0);
  border-radius: 0;
}
.ds-btn-primary:hover {
  background: #e8e1d4;
  transform: translateY(-1px);
}
.ds-btn-primary:active, .ds-btn-primary.ds-btn-primary-active {
  background: #1a1612;
  color: #fbf8f3;
  transform: translateY(-1px);
  box-shadow: 2px 2px 0 #c44536;
}
.ds-btn-primary:focus-visible {
  outline: 2px solid #c44536;
  outline-offset: 2px;
}

.ds-example {
  background: rgba(45,93,61,0.06);
  border-left: 4px solid #2d5d3d;
  padding: 20px 26px;
  margin: 20px 0;
  color: #1a1612;
  font-family: 'Fraunces', Georgia, serif;
  line-height: 1.65;
  border-radius: 0;
}
.ds-example-tag {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.25em;
  color: #2d5d3d;
  margin-bottom: 6px;
  text-transform: uppercase;
}
.ds-example p {
  max-width: none;
}

.ds-chapter-mark {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: #c44536;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 12px;
}
.ds-chapter-mark::after {
  content: "";
  flex: 1;
  height: 1px;
  background: #2a221c;
  opacity: 0.3;
}

.ds-masthead {
  border-bottom: 3px double #2a221c;
  padding: 24px 6vw 18px;
  background: #fbf8f3;
  position: relative;
}
.ds-masthead-top {
  display: flex;
  justify-content: space-between;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 11px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: #6b5d4f;
  border-bottom: 1px solid #2a221c;
  padding-bottom: 10px;
  margin-bottom: 18px;
}
.ds-masthead-title {
  font-family: 'Fraunces', Georgia, serif;
  font-weight: 300;
  font-size: clamp(48px, 9vw, 110px);
  line-height: 0.92;
  letter-spacing: -0.04em;
  text-align: center;
}
.ds-masthead-title em {
  font-style: italic;
  font-weight: 500;
  color: #c44536;
}
.ds-masthead-sub {
  text-align: center;
  margin-top: 14px;
  font-style: italic;
  font-size: 18px;
  color: #6b5d4f;
  font-weight: 400;
  font-family: 'Fraunces', Georgia, serif;
}
.ds-masthead-meta {
  display: flex;
  justify-content: center;
  gap: 32px;
  margin-top: 18px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 11px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}
.ds-masthead-meta span::before {
  content: "§ ";
  color: #c44536;
}

.ds-math-display {
  margin: 12px 0;
  text-align: center;
  overflow-x: auto;
  overflow-y: hidden;
}
.ds-math-display .katex {
  font-size: 1em !important;
}
.ds-math-display .katex-display {
  margin: 0 !important;
}
